void on_rule_satisfied(const rule_t *rule, int verdict, uint64_t timestamp, uint64_t counter,
                       const mmt_array_t *trace)
{
  if (verdict == DETECTED) {
    char alert[1024];
    snprintf(alert, sizeof(alert), "Invalid GTP-U TEID or session inconsistency detected: %s", rule->description);
    mmt_alert(ALERT_LEVEL_HIGH, alert, trace);
  }
}
